import Layout from "../components/layout"
import { connect } from "react-redux"
import {openMenu,removeClassFromCursor,addClassToCursor,setMenuBtnColor} from "../redux/actions"

class Projects extends React.Component {

    constructor(props) {
        super(props);
        this.state = {animate:false,selectedCategory:"all",projectsHide:false,isMobile:false}
      }  


      render(){

     
    return(


        <Layout page="404" navPosition="absolute" navTextColor="black" menuBtnColor="black" hindiText="white" footerType="yellow">
        <div>
            
        <div className={`top position-relative ${this.state.animate?"animate":""}`} style={{minHeight:`${this.props.common.windowHeight*0.95}px`}}>
            
            
            </div>
        </div>

        </Layout>
    ) 
  }
}
function mapStateToProps({ common }) {
    return {
      common,
    };
  }
  export default connect(mapStateToProps, {openMenu,setMenuBtnColor})(Projects);
